#include <bits/stdc++.h>
using namespace std;
int main(){
    int n, m; cin >> n >> m;
    vector<vector<int>> g(n + 1);
    for (int i = 0; i < m; i++){
        int u, v; cin >> u >> v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    vector<bool> vis(n + 1, false);
    function<void(int)> dfs = [&](int u){
        vis[u] = true;
        for (int v : g[u]) if (!vis[v]) dfs(v);
    };
    int cnt = 0;
    for (int i = 1; i <= n; i++) if (!vis[i]) { dfs(i); cnt++; }
    cout << cnt << '\n';
}
